sql:
SELECT library_id
FROM patron_metrics
WHERE total_active_patrons = (
  SELECT MAX(total_active_patrons)
  FROM patron_metrics
);

external_knowledge:
- 'Total collaborations' refers to all collaborations a library is part of, regardless of their status; 
- 'Total allocated budget' is the sum of budgets for all collaborations a library is involved in; 
- 'Completed collaborations' refers to collaborations with a status of 'completed'; 
- 'Unique participating libraries' are libraries that have participated in at least one collaboration with the library in question.

sql:
SELECT l.library_name, pm.patrons_served_last_month
FROM libraries l
JOIN patron_metrics pm ON l.library_id = pm.library_id;

SELECT SUM(budget_spent) AS total_budget_spent
FROM collaborations
WHERE project_status IN ('in progress', 'completed');

SELECT l.library_name, fm.budget
FROM libraries l
JOIN financial_metrics fm ON l.library_id = fm.library_id;
